package main

import (
	"crypto/rand"
	"encoding/hex"
	"errors"
	"net/http"
	"net/url"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// 1. Validate the user-provided redirectPath to prevent Open Redirect vulnerabilities.
	parsedRedirectURL, err := url.Parse(redirectPath)
	if err != nil {
		return "", errors.New("invalid redirect URL format")
	}

	// Parse the base URL from the global config to get the allowed host
	baseURL, err := url.Parse(OAuthConfig.RedirectURL)
	if err != nil {
		return "", errors.New("invalid base OAuth config URL")
	}

	// If the user provided a full URL with a host, ensure it matches the application's host.
	// This prevents attackers from redirecting users to a malicious domain to steal authorization codes.
	if parsedRedirectURL.IsAbs() && parsedRedirectURL.Host != baseURL.Host {
		return "", errors.New("redirect URL host does not match allowed host")
	}

	// 2. Generate a secure, random state string to prevent CSRF attacks.
	// The original code used a hardcoded string which is insecure.
	b := make([]byte, 16)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	randomState := hex.EncodeToString(b)

	// 3. Bind the state to the session if provided.
	// This ensures that the authorization flow is tied to the specific user session.
	var state string
	if session != nil && session.Value != "" {
		state = session.Value + ":" + randomState
	} else {
		state = randomState
	}

	// Create a copy of the OAuth config with the validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectPath

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	return authURL, nil
}

