func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Security Fix 1: Validate the user-provided redirect URL to prevent Open Redirect attacks.
	// Ensure the URL belongs to the allowed host (the request host).
	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return "", errors.New("invalid redirect URL format")
	}

	var finalRedirectURL string

	if parsedURL.IsAbs() {
		// If absolute, ensure it matches the request host to prevent open redirects
		if parsedURL.Host != r.Host {
			return "", errors.New("untrusted redirect URL: host does not match request")
		}
		finalRedirectURL = redirectPath
	} else {
		// If relative, construct absolute URL from request context
		scheme := "http"
		if r.TLS != nil {
			scheme = "https"
		}
		if r.URL.Scheme != "" {
			scheme = r.URL.Scheme
		}
		finalRedirectURL = scheme + "://" + r.Host + redirectPath
	}

	// Security Fix 2: Generate a cryptographically random state parameter to prevent CSRF.
	// The previous implementation used a hardcoded string, which is insecure.
	b := make([]byte, 16)
	if _, err := rand.Read(b); err != nil {
		return "", errors.New("failed to generate secure state")
	}
	state := hex.EncodeToString(b)

	// Create a copy of the OAuth config with the validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = finalRedirectURL

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	// Security attributes: HttpOnly, Secure, and SameSite are set to mitigate XSS and CSRF risks.
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	return authURL, nil
}

