package main

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
	"net/http"
	"net/url"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a secure random state parameter to prevent CSRF attacks
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", fmt.Errorf("failed to generate state: %w", err)
	}
	state := base64.URLEncoding.EncodeToString(b)

	// Construct the full redirect URL. If redirectPath is relative, derive it from the request.
	var finalRedirectURL string
	if u, err := url.Parse(redirectPath); err == nil && u.Scheme == "" {
		// It is a relative path, construct absolute URL
		scheme := "http"
		if r.TLS != nil {
			scheme = "https"
		}
		// Check for X-Forwarded-Proto header in case of proxy
		if proto := r.Header.Get("X-Forwarded-Proto"); proto != "" {
			scheme = proto
		}
		finalRedirectURL = fmt.Sprintf("%s://%s%s", scheme, r.Host, redirectPath)
	} else {
		// It is an absolute URL
		finalRedirectURL = redirectPath
	}

	// Create a copy of the global OAuthConfig to avoid race conditions
	// and set the dynamic redirect URL for this specific request.
	configCopy := *OAuthConfig
	configCopy.RedirectURL = finalRedirectURL

	// Create a cookie to store the state for verification in the callback handler.
	// We attempt to inherit security settings (Domain, Secure, SameSite) from the provided session cookie.
	stateCookie := &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		Path:     "/",
		HttpOnly: true,
		Secure:   true, // Default to Secure
		SameSite: http.SameSiteLaxMode,
	}

	if session != nil {
		if session.Domain != "" {
			stateCookie.Domain = session.Domain
		}
		stateCookie.Secure = session.Secure
		stateCookie.SameSite = session.SameSite
	}

	http.SetCookie(w, stateCookie)

	// Generate the authorization URL with the state.
	authURL := configCopy.AuthCodeURL(state, oauth2.AccessTypeOffline, oauth2.ApprovalForce)

	return authURL, nil
}

